mapper.select:
SELECT DISTINCT a.* FROM xm_course a
LEFT JOIN xm_course_tag b ON a.id = b.course_id
WHERE a.is_delete=0

    AND b.dict_value = #{t.tag}


    AND a.course_name like CONCAT('%',#{t.courseName},'%')


    AND a.course_type = #{t.courseType}


    AND a.type = #{t.type}

ORDER BY a.id desc

select id, course_code courseCode, course_name, ifnull(hour, 0) courseHours, (select ifnull(sum(learn_hours), 0) from xm_course_relation_courseware a left join xm_courseware b on a.courseware_id = b.id where a.is_delete = 0 and b.is_delete = 0 and a.course_id = c.id) learnHours, (select count(1) from xm_course_question where course_id = c.id and is_delete = 0) topicNumber from xm_course c where id in
#{item}
AND course_name like CONCAT('%',#{courseName},'%')

select distinct a.*
from xm_course a
left join xm_course_tag b on a.id = b.course_id and b.is_delete = 0
where a.is_delete = 0
and a.type = #{type}

    and a.course_type = #{classType}


    and a.course_name like concat('%', #{name}, '%')


    and b.dict_value in

        #{item}


ORDER BY a.id DESC
